element */
 svg.dark {
   --ajo-primary: #4D7EFF;
   --ajo-primary-dark: #0035F0;
   --ajo-primary-light: #6B96FF;
   --ajo-success: #4ADE80;
 }

 #loader-ring {
   transform-origin: 100px 100px;
   animation: ajo-spin 2.4s linear infinite;
 }

 #loader-mark {
   transform-origin: 100px 105px;
   animation: ajo-pulse 1.7s ease-in-out infinite;
 }

 @keyframes ajo-spin {
   from { transform: rotate(0deg); }
   to   { transform: rotate(360deg); }
 }

 @keyframes ajo-pulse {
   0%, 100% { transform: scale(1); }
   50%      { transform: scale(1.08); }
 }
